// Parse Fathom email for meeting data
const email = $input.all()[0].json;
const body = email.text || email.snippet || '';
const htmlBody = email.html || '';

// Extract meeting title from subject
// Fathom subjects typically: "Meeting notes: [Title]" or "[Title] - Meeting Summary"
const subject = email.subject || '';
let meetingTitle = subject
  .replace(/^(Meeting notes:|Meeting summary:|Notes from)\s*/i, '')
  .replace(/\s*-\s*(Meeting Summary|Notes)$/i, '')
  .trim();

// Extract date from email headers
const meetingDate = email.date || new Date().toISOString();

// Extract attendees - look for common Fathom patterns
const attendeePatterns = [
  /Attendees?:?\s*([^\n]+)/i,
  /Participants?:?\s*([^\n]+)/i,
  /With:?\s*([^\n]+)/i
];

let attendees = '';
for (const pattern of attendeePatterns) {
  const match = body.match(pattern);
  if (match) { attendees = match[1].trim(); break; }
}

// Extract summary section
const summaryMatch = body.match(/(?:Summary|Overview)[:\s]*\n([\s\S]*?)(?=\n(?:Action Items|Key Points|Decisions|$))/i);
const summary = summaryMatch ? summaryMatch[1].trim() : body.substring(0, 2000);

// Extract action items section
const actionItemsMatch = body.match(/(?:Action Items|Next Steps|Tasks)[:\s]*\n([\s\S]*?)(?=\n(?:Key Points|Decisions|Summary|$))/i);
const actionItems = actionItemsMatch ? actionItemsMatch[1].trim() : 'None auto-detected';

// Extract attendee email domains for client matching
const emailDomains = [];
const emailRegex = /[\w.-]+@([\w.-]+\.\w+)/g;
let emailMatch;
while ((emailMatch = emailRegex.exec(attendees + ' ' + body)) !== null) {
  const domain = emailMatch[1].toLowerCase();
  if (!domain.includes('gmail.com') && !domain.includes('fathom')) {
    emailDomains.push(domain);
  }
}

return [{
  json: {
    meeting_title: meetingTitle,
    meeting_date: meetingDate,
    attendees: attendees,
    attendee_domains: [...new Set(emailDomains)],
    fathom_summary: summary,
    fathom_action_items: actionItems,
    raw_email_body: body,
    email_id: email.id
  }
}];

// Try to match client from attendee domains
const data = $input.all()[0].json;
const domains = data.attendee_domains || [];

// We'll call client-lookup for each domain and return the first match
// For the sub-workflow call, pass the first domain
return [{
  json: {
    ...data,
    lookup_type: 'email_domain',
    lookup_value: domains[0] || 'unknown'
  }
}];

// Merge parsed email data with client config
const emailData = $('Parse Fathom Email').first().json;
const clientData = $input.all()[0].json;

return [{
  json: {
    ...emailData,
    client: clientData,
    client_found: clientData.found || false,
    client_name: clientData.client_name || 'Unknown Client'
  }
}];

values.value:
=Analyze this meeting summary and extract all actionable intelligence.

**Meeting Info:**
- Title: {{ $json.meeting_title }}
- Date: {{ $json.meeting_date }}
- Attendees: {{ $json.attendees }}
- Client: {{ $json.client_name }}

**Fathom Summary:**
{{ $json.fathom_summary }}

**Fathom Action Items (auto-detected):**
{{ $json.fathom_action_items }}

---

Respond with JSON containing: executive_summary, action_items (array with action, owner, priority, deadline, category, context, clickup_list), risk_flags (array with type, severity, description, recommended_action), key_decisions (array), next_meeting_suggestions (array), sentiment, engagement_health_delta.

