// Parse Claude's analysis and prepare ClickUp tasks
const analysis = $input.all()[0].json;
const meetingData = $('Merge Email + Client Data').first().json;
const parsed = typeof analysis.parsed_content === 'string' 
  ? JSON.parse(analysis.parsed_content) 
  : analysis.parsed_content;

// Map action items to ClickUp task format
const tasks = (parsed.action_items || []).map(item => ({
  name: item.action,
  description: `**Owner:** ${item.owner}
**Priority:** ${item.priority}
**Deadline:** ${item.deadline}
**Category:** ${item.category}
**Context:** ${item.context}

_From meeting: ${meetingData.meeting_title} (${meetingData.meeting_date})_`,
  priority: item.priority === 'high' ? 1 : item.priority === 'medium' ? 2 : 3,
  list_type: item.clickup_list,
  due_date: item.deadline !== 'ASAP' && item.deadline !== 'next meeting' ? item.deadline : null
}));

// Check for high-severity risk flags
const highRisks = (parsed.risk_flags || []).filter(r => r.severity === 'high');

return [{
  json: {
    ...meetingData,
    analysis: parsed,
    tasks: tasks,
    high_risks: highRisks,
    has_high_risks: highRisks.length > 0,
    meeting_notes_content: `# ${meetingData.meeting_title}

**Date:** ${meetingData.meeting_date}
**Attendees:** ${meetingData.attendees}
**Client:** ${meetingData.client_name}

## Executive Summary
${parsed.executive_summary}

## Action Items
${(parsed.action_items || []).map(i => `- [${i.owner}] ${i.action} (${i.priority} priority, due: ${i.deadline})`).join('
')}

## Key Decisions
${(parsed.key_decisions || []).map(d => `- ${d.decision}: ${d.rationale}`).join('
')}

## Risk Flags
${(parsed.risk_flags || []).map(r => `- [${r.severity}] ${r.type}: ${r.description}`).join('
')}

## Next Meeting Suggestions
${(parsed.next_meeting_suggestions || []).map(s => `- ${s}`).join('
')}

---
_Sentiment: ${parsed.sentiment} | Engagement Trend: ${parsed.engagement_health_delta}_`
  }
}];

// Split tasks into individual items for ClickUp creation
const data = $input.all()[0].json;
return data.tasks.map(task => ({ json: { ...task, client: data.client } }));
